//! Sovereign LTX-Video 3D DiT — Phase 1: a single transformer block + the LIVE
//! 3D (frame,height,width) rotary position embedding, reference-diffed against
//! diffusers `LTXVideoTransformerBlock` to cos≈1.0.
//!
//! Structure (from diffusers `transformer_ltx.py`, authoritative):
//!   norm1: RMSNorm(dim, elementwise_affine=False)  -> adaLN modulate (shift/scale_msa)
//!   attn1: self-attn  q/k/v separate (2048->2048), qk RMSNorm ACROSS HEADS (over
//!          full 2048) BEFORE 3D RoPE, RoPE on q&k, SDPA, to_out
//!          hidden = hidden + gate_msa * attn1
//!   attn2: cross-attn q from hidden, k/v from encoder_hidden_states (caption,
//!          already 2048-dim at block level), qk RMSNorm across heads, NO RoPE,
//!          SDPA. hidden = hidden + attn2   (NO gate on cross-attn)
//!   norm2: RMSNorm -> adaLN modulate (shift/scale_mlp)
//!   ff:    Linear(2048->8192) + tanh-GELU + Linear(8192->2048)  (non-gated)
//!          hidden = hidden + gate_mlp * ff
//!
//! adaLN: per-block `scale_shift_table` [6,dim] is ADDED to a per-(token) temb of
//!   shape [.,6*dim], split into (shift_msa,scale_msa,gate_msa,shift_mlp,scale_mlp,
//!   gate_mlp). modulate: norm * (1 + scale) + shift. The diffusers code does
//!   `norm * (1 + scale_msa) + shift_msa` (scale is an additive +1 offset).
//!
//! 3D RoPE (LTXVideoRotaryPosEmbed, dim = inner_dim = 2048, applied to the FULL
//!   flat q/k BEFORE head split): positions are a frame-major flatten of the
//!   (F,H,W) grid (token t = f*H*W + h*W + w). dim//6 = 341 freqs per axis;
//!   freq[k] = theta^(linspace(0,1,341)[k]) * (pi/2) * (coord*2 - 1); the three
//!   axes interleave n-major: [a0_k0,a1_k0,a2_k0, a0_k1,...]; each freq is
//!   repeat_interleave(2) so it covers one consecutive (even,odd) pair; a front
//!   pad of dim%6 = 2 identity dims (cos=1,sin=0) is prepended. Rotation pairs
//!   are consecutive (x[2i],x[2i+1]).
//!
//! All weights from ltx-video.knot (Q8_0 linears, F32 norms/biases). Pure CPU f32.

#![cfg(not(target_arch = "wasm32"))]

use crate::loader::{fetch_knot_tensor_bytes_from_metadata, KnotWeights};
use crate::math::{dot_product, gelu_inplace, mat_vec_q8_0_rows_shared, softmax};

pub const LTX_HIDDEN: usize = 2048;
pub const LTX_HEADS: usize = 32;
pub const LTX_HEAD_DIM: usize = 64;
pub const LTX_FF_INNER: usize = 8192;
pub const LTX_THETA: f32 = 10_000.0;
// RoPE coordinate scaling (LTXVideoRotaryPosEmbed defaults + pipeline micro-conds).
// The diffusers pipeline ALWAYS passes rope_interpolation_scale, so the scaling
// branch in _prepare_video_coords is taken: each grid axis is multiplied by
// (rope_interpolation_scale[axis] * patch_size_axis / base_axis). With the raw
// (unscaled) integer coords used previously the cos table COLLAPSED: cos is even
// in (2*coord-1), so neighbouring positions (w, w+1) → cos(±f)=cos(f) became
// IDENTICAL, and high-k freqs aliased, yielding a per-latent-cell banding field
// instead of a smoothly varying positional code. These constants restore the
// reference scaling. (LTX-Video defaults: spatial comp 32, temporal comp 8.)
pub const LTX_VAE_SPATIAL_COMPRESSION: f32 = 32.0;
pub const LTX_VAE_TEMPORAL_COMPRESSION: f32 = 8.0;
pub const LTX_DEFAULT_FRAME_RATE: f32 = 25.0;
pub const LTX_PATCH_SIZE: f32 = 1.0;
pub const LTX_PATCH_SIZE_T: f32 = 1.0;
pub const LTX_BASE_NUM_FRAMES: f32 = 20.0;
pub const LTX_BASE_HEIGHT: f32 = 2048.0;
pub const LTX_BASE_WIDTH: f32 = 2048.0;
const RMS_EPS: f32 = 1e-5; // attn qk RMSNorm eps (torch.nn.RMSNorm default in LTXAttention)
const NORM_EPS: f32 = 1e-6; // block norm1/norm2 RMSNorm eps

// ─────────────────────────── tensor fetch ───────────────────────────

fn fetch_q8(knot_source: &str, knot: &KnotWeights, name: &str) -> Result<Vec<u8>, String> {
    let t = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        name,
    )
    .map_err(|e| format!("fetch {name}: {e}"))?;
    if !t.info.tensor_type.eq_ignore_ascii_case("Q8_0") {
        return Err(format!("{name} must be Q8_0, got {}", t.info.tensor_type));
    }
    Ok(t.bytes)
}

fn fetch_f32(knot_source: &str, knot: &KnotWeights, name: &str) -> Result<Vec<f32>, String> {
    let t = fetch_knot_tensor_bytes_from_metadata(
        knot_source,
        &knot.metadata,
        knot.payload_offset,
        name,
    )
    .map_err(|e| format!("fetch {name}: {e}"))?;
    if !t.info.tensor_type.eq_ignore_ascii_case("F32")
        && !t.info.tensor_type.eq_ignore_ascii_case("fp32")
    {
        return Err(format!("{name} must be F32, got {}", t.info.tensor_type));
    }
    let n = t.bytes.len() / 4;
    let mut out = vec![0.0f32; n];
    for (i, chunk) in t.bytes.chunks_exact(4).enumerate() {
        out[i] = f32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]);
    }
    Ok(out)
}

/// Q8_0 weight + F32 bias linear layer.
struct Linear {
    w: Vec<u8>,
    b: Vec<f32>,
    rows: usize,
    cols: usize,
}

impl Linear {
    fn load(
        knot_source: &str,
        knot: &KnotWeights,
        weight_name: &str,
        bias_name: &str,
        rows: usize,
        cols: usize,
    ) -> Result<Self, String> {
        Ok(Self {
            w: fetch_q8(knot_source, knot, weight_name)?,
            b: fetch_f32(knot_source, knot, bias_name)?,
            rows,
            cols,
        })
    }
    /// Batched apply over `tokens` inputs of length cols, flat [tokens*cols] ->
    /// flat [tokens*rows]. Bias added per row.
    fn apply_batch(&self, xs: &[f32], tokens: usize) -> Vec<f32> {
        let mut out = vec![0.0f32; tokens * self.rows];
        mat_vec_q8_0_rows_shared(&mut out, xs, &self.w, self.rows, self.cols, tokens);
        for t in 0..tokens {
            let o = t * self.rows;
            for r in 0..self.rows {
                out[o + r] += self.b[r];
            }
        }
        out
    }
}

// ─────────────────────────── norms ───────────────────────────

/// RMSNorm over the full last dim with elementwise-affine weight (eps configurable).
/// diffusers RMSNorm: x * rsqrt(mean(x^2)+eps) * weight.
fn rms_norm_affine(out: &mut [f32], x: &[f32], w: &[f32], eps: f32) {
    let n = x.len() as f32;
    let ms = x.iter().map(|v| v * v).sum::<f32>() / n;
    let inv = 1.0 / (ms + eps).sqrt();
    for ((o, &xv), &wv) in out.iter_mut().zip(x.iter()).zip(w.iter()) {
        *o = xv * inv * wv;
    }
}

/// RMSNorm over the full last dim WITHOUT affine (elementwise_affine=False),
/// used by block norm1/norm2 (diffusers RMSNorm with weight=None just normalizes).
fn rms_norm_no_affine(out: &mut [f32], x: &[f32], eps: f32) {
    let n = x.len() as f32;
    let ms = x.iter().map(|v| v * v).sum::<f32>() / n;
    let inv = 1.0 / (ms + eps).sqrt();
    for (o, &xv) in out.iter_mut().zip(x.iter()) {
        *o = xv * inv;
    }
}

// ─────────────────────────── 3D RoPE (LIVE frame,h,w) ───────────────────────────

/// LTX 3D rotary table over the full `dim` (= LTX_HIDDEN). Stores per-token
/// cos/sin of length `dim` (already repeat-interleaved + front-padded), so the
/// rotation of a flat q/k token vector is a direct elementwise op on consecutive
/// (even,odd) pairs.
pub struct Rope3D {
    cos: Vec<f32>, // [tokens * dim]
    sin: Vec<f32>, // [tokens * dim]
    #[allow(dead_code)]
    tokens: usize,
    dim: usize,
}

impl Rope3D {
    /// Build over a (frames,height,width) grid, frame-major flatten.
    ///
    /// CRITICAL: the diffusers LTX pipeline ALWAYS supplies `rope_interpolation_scale`
    /// (= (vae_temporal/frame_rate, vae_spatial, vae_spatial)), so each axis coord is
    /// SCALED by `rope_interpolation_scale[axis] * patch_size_axis / base_axis` before
    /// the `coord*2 - 1` map. Using raw integer coords (the previous behaviour) made
    /// the cos table collapse — cos is even in `2*coord-1`, so adjacent positions
    /// (e.g. w=0 vs w=1 → cos(±base_freq)=same) became IDENTICAL and the high-k freqs
    /// aliased, producing the per-latent-cell banding. We now match the reference
    /// scaling exactly.
    pub fn build(frames: usize, height: usize, width: usize, dim: usize, theta: f32) -> Self {
        let tokens = frames * height * width;
        let per_axis = dim / 6; // 341 for dim=2048
        let pad = dim % 6; // 2 for dim=2048
        // per-axis coordinate scale: rope_interpolation_scale[axis] * patch / base.
        let (scale_f, scale_h, scale_w) = if std::env::var("LTX_ROPE_RAW").is_ok() {
            // DEBUG ONLY: reproduce the previous (buggy) raw-integer-coord behaviour
            // for A/B banding comparison. Not used in production.
            (1.0f32, 1.0f32, 1.0f32)
        } else {
            (
                (LTX_VAE_TEMPORAL_COMPRESSION / LTX_DEFAULT_FRAME_RATE) * LTX_PATCH_SIZE_T
                    / LTX_BASE_NUM_FRAMES,
                LTX_VAE_SPATIAL_COMPRESSION * LTX_PATCH_SIZE / LTX_BASE_HEIGHT,
                LTX_VAE_SPATIAL_COMPRESSION * LTX_PATCH_SIZE / LTX_BASE_WIDTH,
            )
        };
        // freqs[k] = theta^(linspace(log_theta(1)=0 .. log_theta(theta)=1, per_axis)[k]) * pi/2
        let mut base_freq = vec![0.0f32; per_axis];
        for k in 0..per_axis {
            let frac = if per_axis > 1 {
                k as f32 / (per_axis as f32 - 1.0)
            } else {
                0.0
            };
            base_freq[k] = theta.powf(frac) * (std::f32::consts::PI / 2.0);
        }
        let mut cos = vec![1.0f32; tokens * dim];
        let mut sin = vec![0.0f32; tokens * dim];
        for f in 0..frames {
            for h in 0..height {
                for w in 0..width {
                    let tok = (f * height + h) * width + w; // frame-major
                    let coords = [
                        f as f32 * scale_f,
                        h as f32 * scale_h,
                        w as f32 * scale_w,
                    ];
                    // freqs[axis,k] = base_freq[k] * (coord*2 - 1); flattened n-major:
                    // order = [a0_k0,a1_k0,a2_k0, a0_k1,a1_k1,a2_k1, ...]; each freq
                    // covers one (even,odd) pair via repeat_interleave(2). Front pad
                    // of `pad` identity dims.
                    let base = tok * dim;
                    // front pad: indices [0..pad) stay cos=1/sin=0 (already set)
                    let mut flat_idx = 0usize; // index into the (per_axis*3) freq list
                    for k in 0..per_axis {
                        for axis in 0..3 {
                            let angle = base_freq[k] * (coords[axis] * 2.0 - 1.0);
                            // pair position in the dim vector (after front pad):
                            let pair = flat_idx; // 0-based pair index
                            let i0 = base + pad + 2 * pair;
                            let i1 = i0 + 1;
                            let (s, c) = angle.sin_cos();
                            cos[i0] = c;
                            cos[i1] = c;
                            sin[i0] = s;
                            sin[i1] = s;
                            flat_idx += 1;
                        }
                    }
                    debug_assert_eq!(pad + 2 * flat_idx, dim);
                }
            }
        }
        Rope3D {
            cos,
            sin,
            tokens,
            dim,
        }
    }

    /// Apply to one token's full flat vector [dim] in place: consecutive pairs
    /// (x[2i],x[2i+1]) rotated by the token's (cos,sin). apply_rotary_emb does:
    ///   x_rotated = [-x_odd, x_even];  out = x*cos + x_rotated*sin
    ///   out_even = x_even*cos - x_odd*sin ; out_odd = x_odd*cos + x_even*sin
    pub fn apply_token(&self, v: &mut [f32], token: usize) {
        debug_assert_eq!(v.len(), self.dim);
        let base = token * self.dim;
        let mut i = 0usize;
        while i + 1 < self.dim {
            let c0 = self.cos[base + i];
            let s0 = self.sin[base + i];
            // c0==c1 and s0==s1 by construction (repeat_interleave), so use c0/s0.
            let x_even = v[i];
            let x_odd = v[i + 1];
            v[i] = x_even * c0 - x_odd * s0;
            v[i + 1] = x_odd * c0 + x_even * s0;
            i += 2;
        }
    }
}

// ─────────────────────────── attention ───────────────────────────

/// Multi-head attention. q is [q_tokens*HIDDEN], k/v are [kv_tokens*HIDDEN].
/// Output [q_tokens*HIDDEN]. Non-causal, no mask (encoder mask is None in the
/// reference). Heads are contiguous bands of HEAD_DIM within the flat HIDDEN.
fn attention(
    q: &[f32],
    k: &[f32],
    v: &[f32],
    q_tokens: usize,
    kv_tokens: usize,
) -> Result<Vec<f32>, String> {
    use gnosis_frf::prelude::*;
    let mut out = vec![0.0f32; q_tokens * LTX_HIDDEN];
    let scale = 1.0 / (LTX_HEAD_DIM as f32).sqrt();
    let out_ptr = out.as_mut_ptr() as usize;
    (0..LTX_HEADS).into_par_iter().for_each(|head| {
        let ho = head * LTX_HEAD_DIM;
        let mut scores = vec![0.0f32; kv_tokens];
        for ti in 0..q_tokens {
            let qs = ti * LTX_HIDDEN + ho;
            let qh = &q[qs..qs + LTX_HEAD_DIM];
            for tj in 0..kv_tokens {
                let ks = tj * LTX_HIDDEN + ho;
                scores[tj] = dot_product(qh, &k[ks..ks + LTX_HEAD_DIM]) * scale;
            }
            softmax(&mut scores);
            let os = ti * LTX_HIDDEN + ho;
            for tj in 0..kv_tokens {
                let wgt = scores[tj];
                let vs = tj * LTX_HIDDEN + ho;
                for d in 0..LTX_HEAD_DIM {
                    // SAFETY: head's exclusive column band; no overlap across heads.
                    unsafe {
                        let p = (out_ptr as *mut f32).add(os + d);
                        *p += wgt * v[vs + d];
                    }
                }
            }
        }
    });
    if out.iter().any(|x| !x.is_finite()) {
        return Err("ltx attention produced non-finite output".into());
    }
    Ok(out)
}

// ─────────────────────────── block ───────────────────────────

struct LtxAttn {
    to_q: Linear,
    to_k: Linear,
    to_v: Linear,
    to_out: Linear,
    norm_q: Vec<f32>, // [HIDDEN] rms_norm_across_heads weight
    norm_k: Vec<f32>,
}

impl LtxAttn {
    fn load(
        knot_source: &str,
        knot: &KnotWeights,
        prefix: &str, // e.g. "ltx_dit_transformer_blocks_0_attn1_"
    ) -> Result<Self, String> {
        // Knot metadata keys have the `.bin` suffix stripped by parse_tensors.
        let p = |s: &str| format!("{prefix}{s}");
        Ok(Self {
            to_q: Linear::load(
                knot_source,
                knot,
                &p("to_q_weight"),
                &p("to_q_bias"),
                LTX_HIDDEN,
                LTX_HIDDEN,
            )?,
            to_k: Linear::load(
                knot_source,
                knot,
                &p("to_k_weight"),
                &p("to_k_bias"),
                LTX_HIDDEN,
                LTX_HIDDEN,
            )?,
            to_v: Linear::load(
                knot_source,
                knot,
                &p("to_v_weight"),
                &p("to_v_bias"),
                LTX_HIDDEN,
                LTX_HIDDEN,
            )?,
            to_out: Linear::load(
                knot_source,
                knot,
                &p("to_out_0_weight"),
                &p("to_out_0_bias"),
                LTX_HIDDEN,
                LTX_HIDDEN,
            )?,
            norm_q: fetch_f32(knot_source, knot, &p("norm_q_weight"))?,
            norm_k: fetch_f32(knot_source, knot, &p("norm_k_weight"))?,
        })
    }

    /// hidden: [q_tokens*HIDDEN] (query source). enc: [kv_tokens*HIDDEN] (key/value
    /// source; == hidden for self-attn). rope applied to q&k only when Some.
    fn forward(
        &self,
        hidden: &[f32],
        enc: &[f32],
        q_tokens: usize,
        kv_tokens: usize,
        rope: Option<&Rope3D>,
    ) -> Result<Vec<f32>, String> {
        let mut q = self.to_q.apply_batch(hidden, q_tokens);
        let mut k = self.to_k.apply_batch(enc, kv_tokens);
        let v = self.to_v.apply_batch(enc, kv_tokens);

        // rms_norm_across_heads: RMSNorm over the full HIDDEN of each token, with
        // affine weight, applied to q and k (BEFORE RoPE, per the processor order).
        for t in 0..q_tokens {
            let s = t * LTX_HIDDEN;
            let mut tmp = vec![0.0f32; LTX_HIDDEN];
            rms_norm_affine(&mut tmp, &q[s..s + LTX_HIDDEN], &self.norm_q, RMS_EPS);
            q[s..s + LTX_HIDDEN].copy_from_slice(&tmp);
        }
        for t in 0..kv_tokens {
            let s = t * LTX_HIDDEN;
            let mut tmp = vec![0.0f32; LTX_HIDDEN];
            rms_norm_affine(&mut tmp, &k[s..s + LTX_HIDDEN], &self.norm_k, RMS_EPS);
            k[s..s + LTX_HIDDEN].copy_from_slice(&tmp);
        }

        if let Some(rope) = rope {
            for t in 0..q_tokens {
                let s = t * LTX_HIDDEN;
                rope.apply_token(&mut q[s..s + LTX_HIDDEN], t);
            }
            for t in 0..kv_tokens {
                let s = t * LTX_HIDDEN;
                rope.apply_token(&mut k[s..s + LTX_HIDDEN], t);
            }
        }

        let attn = attention(&q, &k, &v, q_tokens, kv_tokens)?;
        Ok(self.to_out.apply_batch(&attn, q_tokens))
    }
}

pub struct LtxBlock {
    attn1: LtxAttn,
    attn2: LtxAttn,
    ff_in: Linear,
    ff_out: Linear,
    scale_shift_table: Vec<f32>, // [6*HIDDEN]
}

impl LtxBlock {
    pub fn load(knot_source: &str, knot: &KnotWeights, layer: usize) -> Result<Self, String> {
        let bp = format!("ltx_dit_transformer_blocks_{layer}_");
        let attn1 = LtxAttn::load(knot_source, knot, &format!("{bp}attn1_"))?;
        let attn2 = LtxAttn::load(knot_source, knot, &format!("{bp}attn2_"))?;
        let ff_in = Linear::load(
            knot_source,
            knot,
            &format!("{bp}ff_net_0_proj_weight"),
            &format!("{bp}ff_net_0_proj_bias"),
            LTX_FF_INNER,
            LTX_HIDDEN,
        )?;
        let ff_out = Linear::load(
            knot_source,
            knot,
            &format!("{bp}ff_net_2_weight"),
            &format!("{bp}ff_net_2_bias"),
            LTX_HIDDEN,
            LTX_FF_INNER,
        )?;
        let scale_shift_table = fetch_f32(knot_source, knot, &format!("{bp}scale_shift_table"))?;
        Ok(Self {
            attn1,
            attn2,
            ff_in,
            ff_out,
            scale_shift_table,
        })
    }

    /// hidden: [img_tokens*HIDDEN] (mutated in place to the block output).
    /// enc: [cap_tokens*HIDDEN] caption (already projected to HIDDEN at block level).
    /// temb: [6*HIDDEN] per-block timestep conditioning (broadcast over tokens,
    ///   matching the reference's [1,1,6*dim] temb). rope: 3D RoPE over img tokens.
    pub fn forward(
        &self,
        hidden: &mut [f32],
        enc: &[f32],
        temb: &[f32],
        img_tokens: usize,
        cap_tokens: usize,
        rope: &Rope3D,
    ) -> Result<(), String> {
        // ada_values = scale_shift_table[6,dim] + temb[6,dim]; split into 6 chunks.
        let mut ada = vec![0.0f32; 6 * LTX_HIDDEN];
        for i in 0..6 * LTX_HIDDEN {
            ada[i] = self.scale_shift_table[i] + temb[i];
        }
        let chunk = |idx: usize| &ada[idx * LTX_HIDDEN..(idx + 1) * LTX_HIDDEN];
        let shift_msa = chunk(0);
        let scale_msa = chunk(1);
        let gate_msa = chunk(2);
        let shift_mlp = chunk(3);
        let scale_mlp = chunk(4);
        let gate_mlp = chunk(5);

        // norm1 + adaLN modulate -> attn1 (self) -> hidden += gate_msa * attn1
        let mut norm_h = vec![0.0f32; img_tokens * LTX_HIDDEN];
        for t in 0..img_tokens {
            let s = t * LTX_HIDDEN;
            let mut tmp = vec![0.0f32; LTX_HIDDEN];
            rms_norm_no_affine(&mut tmp, &hidden[s..s + LTX_HIDDEN], NORM_EPS);
            for d in 0..LTX_HIDDEN {
                norm_h[s + d] = tmp[d] * (1.0 + scale_msa[d]) + shift_msa[d];
            }
        }
        let attn1 = self
            .attn1
            .forward(&norm_h, &norm_h, img_tokens, img_tokens, Some(rope))?;
        for t in 0..img_tokens {
            let s = t * LTX_HIDDEN;
            for d in 0..LTX_HIDDEN {
                hidden[s + d] += attn1[s + d] * gate_msa[d];
            }
        }

        // attn2 (cross to caption), NO RoPE, NO gate.
        let attn2 = self
            .attn2
            .forward(hidden, enc, img_tokens, cap_tokens, None)?;
        for x in 0..img_tokens * LTX_HIDDEN {
            hidden[x] += attn2[x];
        }

        // norm2 + adaLN modulate -> ff -> hidden += gate_mlp * ff
        let mut norm_h2 = vec![0.0f32; img_tokens * LTX_HIDDEN];
        for t in 0..img_tokens {
            let s = t * LTX_HIDDEN;
            let mut tmp = vec![0.0f32; LTX_HIDDEN];
            rms_norm_no_affine(&mut tmp, &hidden[s..s + LTX_HIDDEN], NORM_EPS);
            for d in 0..LTX_HIDDEN {
                norm_h2[s + d] = tmp[d] * (1.0 + scale_mlp[d]) + shift_mlp[d];
            }
        }
        let mut ff = self.ff_in.apply_batch(&norm_h2, img_tokens);
        gelu_inplace(&mut ff);
        let ff = self.ff_out.apply_batch(&ff, img_tokens);
        for t in 0..img_tokens {
            let s = t * LTX_HIDDEN;
            for d in 0..LTX_HIDDEN {
                hidden[s + d] += ff[s + d] * gate_mlp[d];
            }
        }
        if hidden.iter().any(|x| !x.is_finite()) {
            return Err("ltx block produced non-finite output".into());
        }
        Ok(())
    }
}

// ─────────────────────────── full velocity model ───────────────────────────

pub const LTX_IN_CHANNELS: usize = 128;
pub const LTX_OUT_CHANNELS: usize = 128;
pub const LTX_CAPTION_CHANNELS: usize = 4096;
pub const LTX_NUM_LAYERS: usize = 28;
pub const LTX_TIME_EMB_DIM: usize = 256;

#[inline]
fn silu(x: f32) -> f32 {
    x / (1.0 + (-x).exp())
}

/// diffusers get_timestep_embedding(dim=256, flip_sin_to_cos=True,
/// downscale_freq_shift=0, max_period=10000): exponent = -ln(10000)*k/half for
/// k in 0..half(=128); emb = exp(exponent)*t; output = cat([cos(emb), sin(emb)]).
fn timestep_embedding(t: f32) -> Vec<f32> {
    let dim = LTX_TIME_EMB_DIM;
    let half = dim / 2;
    let mut out = vec![0.0f32; dim];
    for k in 0..half {
        let exponent = -(10_000f32.ln()) * (k as f32) / (half as f32);
        let arg = t * exponent.exp();
        out[k] = arg.cos();
        out[half + k] = arg.sin();
    }
    out
}

/// LayerNorm with NO affine (norm_out: elementwise_affine=False, eps=1e-6).
fn layernorm_no_affine(out: &mut [f32], x: &[f32], eps: f32) {
    let n = x.len() as f32;
    let mean = x.iter().sum::<f32>() / n;
    let var = x.iter().map(|v| (v - mean) * (v - mean)).sum::<f32>() / n;
    let inv = 1.0 / (var + eps).sqrt();
    for (o, &xv) in out.iter_mut().zip(x.iter()) {
        *o = (xv - mean) * inv;
    }
}

/// Timestep conditioning (AdaLayerNormSingle):
///   embedded_timestep = timestep_embedder(time_proj(t))  [256 -> 2048]
///     timestep_embedder = linear_1(256->2048) -> silu -> linear_2(2048->2048)
///   temb = time_embed.linear(silu(embedded_timestep))   [2048 -> 6*2048]
struct CondEmbedder {
    ts1: Linear,
    ts2: Linear,
    linear: Linear,
}

impl CondEmbedder {
    fn load(knot_source: &str, knot: &KnotWeights) -> Result<Self, String> {
        let ts1 = Linear::load(
            knot_source,
            knot,
            "ltx_dit_time_embed_emb_timestep_embedder_linear_1_weight",
            "ltx_dit_time_embed_emb_timestep_embedder_linear_1_bias",
            LTX_HIDDEN,
            LTX_TIME_EMB_DIM,
        )?;
        let ts2 = Linear::load(
            knot_source,
            knot,
            "ltx_dit_time_embed_emb_timestep_embedder_linear_2_weight",
            "ltx_dit_time_embed_emb_timestep_embedder_linear_2_bias",
            LTX_HIDDEN,
            LTX_HIDDEN,
        )?;
        let linear = Linear::load(
            knot_source,
            knot,
            "ltx_dit_time_embed_linear_weight",
            "ltx_dit_time_embed_linear_bias",
            6 * LTX_HIDDEN,
            LTX_HIDDEN,
        )?;
        Ok(Self { ts1, ts2, linear })
    }

    /// Returns (temb[6*HIDDEN], embedded_timestep[HIDDEN]).
    fn embed(&self, t: f32) -> (Vec<f32>, Vec<f32>) {
        let proj = timestep_embedding(t);
        let mut h = self.ts1.apply_batch(&proj, 1);
        for x in h.iter_mut() {
            *x = silu(*x);
        }
        let embedded = self.ts2.apply_batch(&h, 1);
        let mut s = embedded.clone();
        for x in s.iter_mut() {
            *x = silu(*x);
        }
        let temb = self.linear.apply_batch(&s, 1);
        (temb, embedded)
    }
}

/// caption_projection (PixArtAlphaTextProjection): linear_1 (4096->2048) ->
/// tanh-GELU -> linear_2 (2048->2048).
struct CaptionProjection {
    l1: Linear,
    l2: Linear,
}

impl CaptionProjection {
    fn load(knot_source: &str, knot: &KnotWeights) -> Result<Self, String> {
        Ok(Self {
            l1: Linear::load(
                knot_source,
                knot,
                "ltx_dit_caption_projection_linear_1_weight",
                "ltx_dit_caption_projection_linear_1_bias",
                LTX_HIDDEN,
                LTX_CAPTION_CHANNELS,
            )?,
            l2: Linear::load(
                knot_source,
                knot,
                "ltx_dit_caption_projection_linear_2_weight",
                "ltx_dit_caption_projection_linear_2_bias",
                LTX_HIDDEN,
                LTX_HIDDEN,
            )?,
        })
    }
    fn apply(&self, caption: &[f32], tokens: usize) -> Vec<f32> {
        let mut h = self.l1.apply_batch(caption, tokens);
        gelu_inplace(&mut h);
        self.l2.apply_batch(&h, tokens)
    }
}

pub struct LtxDit {
    proj_in: Linear,
    cond: CondEmbedder,
    caption: CaptionProjection,
    blocks: Vec<LtxBlock>,
    final_scale_shift: Vec<f32>, // [2*HIDDEN]
    proj_out: Linear,
}

impl LtxDit {
    pub fn load(knot_source: &str, knot: &KnotWeights) -> Result<Self, String> {
        let proj_in = Linear::load(
            knot_source,
            knot,
            "ltx_dit_proj_in_weight",
            "ltx_dit_proj_in_bias",
            LTX_HIDDEN,
            LTX_IN_CHANNELS,
        )?;
        let cond = CondEmbedder::load(knot_source, knot)?;
        let caption = CaptionProjection::load(knot_source, knot)?;
        let mut blocks = Vec::with_capacity(LTX_NUM_LAYERS);
        for l in 0..LTX_NUM_LAYERS {
            blocks.push(LtxBlock::load(knot_source, knot, l)?);
        }
        let final_scale_shift = fetch_f32(knot_source, knot, "ltx_dit_scale_shift_table")?;
        let proj_out = Linear::load(
            knot_source,
            knot,
            "ltx_dit_proj_out_weight",
            "ltx_dit_proj_out_bias",
            LTX_OUT_CHANNELS,
            LTX_HIDDEN,
        )?;
        Ok(Self {
            proj_in,
            cond,
            caption,
            blocks,
            final_scale_shift,
            proj_out,
        })
    }

    /// Full velocity. latents: [img_tokens*IN_CHANNELS]; caption: [cap_tokens*4096].
    /// Returns velocity [img_tokens*OUT_CHANNELS].
    #[allow(clippy::too_many_arguments)]
    pub fn velocity(
        &self,
        latents: &[f32],
        caption: &[f32],
        timestep: f32,
        frames: usize,
        height: usize,
        width: usize,
        cap_tokens: usize,
    ) -> Result<Vec<f32>, String> {
        let img_tokens = frames * height * width;
        let mut hidden = self.proj_in.apply_batch(latents, img_tokens);
        let (temb, embedded) = self.cond.embed(timestep);
        let enc = self.caption.apply(caption, cap_tokens);
        let rope = Rope3D::build(frames, height, width, LTX_HIDDEN, LTX_THETA);

        for block in &self.blocks {
            block.forward(&mut hidden, &enc, &temb, img_tokens, cap_tokens, &rope)?;
        }

        // final adaLN: scale_shift_values = scale_shift_table[2,HIDDEN] + embedded[None]
        //   shift = [:,0], scale = [:,1]; norm_out(hidden)*(1+scale)+shift.
        let shift: Vec<f32> = (0..LTX_HIDDEN)
            .map(|d| self.final_scale_shift[d] + embedded[d])
            .collect();
        let scale: Vec<f32> = (0..LTX_HIDDEN)
            .map(|d| self.final_scale_shift[LTX_HIDDEN + d] + embedded[d])
            .collect();
        let mut normed = vec![0.0f32; img_tokens * LTX_HIDDEN];
        for t in 0..img_tokens {
            let s = t * LTX_HIDDEN;
            let mut tmp = vec![0.0f32; LTX_HIDDEN];
            layernorm_no_affine(&mut tmp, &hidden[s..s + LTX_HIDDEN], 1e-6);
            for d in 0..LTX_HIDDEN {
                normed[s + d] = tmp[d] * (1.0 + scale[d]) + shift[d];
            }
        }
        let vel = self.proj_out.apply_batch(&normed, img_tokens);
        if vel.iter().any(|x| !x.is_finite()) {
            return Err("ltx velocity produced non-finite output".into());
        }
        Ok(vel)
    }
}

// ─────────────────────────── debug dump (block 0) ───────────────────────────

/// Deterministic input generator matching the ref script's det(seed,n).
fn det(seed: i64, n: usize) -> Vec<f32> {
    let mut out = vec![0.0f32; n];
    for (idx, o) in out.iter_mut().enumerate() {
        let i = (idx + 1) as f64;
        let a = i * 0.0007 + seed as f64 * 0.013;
        *o = ((a.sin() * 0.8 + (a * 2.3).cos() * 0.2) * 0.5) as f32;
    }
    out
}

pub struct LtxBlock0Dump {
    pub block_out: Vec<f32>,
    pub img_len: usize,
    pub cap_len: usize,
    pub h: usize,
}

/// Run block-0 forward on the SAME fixed deterministic input as ref_block0.py and
/// return the block output for numeric cross-check.
pub fn debug_block0_forward(
    knot_source: &str,
    knot: &KnotWeights,
    frames: usize,
    height: usize,
    width: usize,
    cap_len: usize,
) -> Result<LtxBlock0Dump, String> {
    let img_len = frames * height * width;
    let block = LtxBlock::load(knot_source, knot, 0)?;
    let mut hidden = det(1, img_len * LTX_HIDDEN);
    let enc = det(2, cap_len * LTX_HIDDEN);
    let temb = det(3, 6 * LTX_HIDDEN);
    let rope = Rope3D::build(frames, height, width, LTX_HIDDEN, LTX_THETA);
    block.forward(&mut hidden, &enc, &temb, img_len, cap_len, &rope)?;
    Ok(LtxBlock0Dump {
        block_out: hidden,
        img_len,
        cap_len,
        h: LTX_HIDDEN,
    })
}

pub struct LtxVelocityDump {
    pub velocity: Vec<f32>,
    pub img_len: usize,
    pub cap_len: usize,
    pub out_channels: usize,
}

/// Full-velocity forward on the same fixed deterministic input as ref_velocity.py:
/// latents seed 1 [img_len*128], caption seed 2 [cap_len*4096], timestep 0.5.
pub fn debug_velocity_forward(
    knot_source: &str,
    knot: &KnotWeights,
    frames: usize,
    height: usize,
    width: usize,
    cap_len: usize,
) -> Result<LtxVelocityDump, String> {
    let img_len = frames * height * width;
    let dit = LtxDit::load(knot_source, knot)?;
    let latents = det(1, img_len * LTX_IN_CHANNELS);
    let caption = det(2, cap_len * LTX_CAPTION_CHANNELS);
    let vel = dit.velocity(&latents, &caption, 0.5, frames, height, width, cap_len)?;
    Ok(LtxVelocityDump {
        velocity: vel,
        img_len,
        cap_len,
        out_channels: LTX_OUT_CHANNELS,
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn rope_dim_partition_is_exact() {
        let dim = LTX_HIDDEN;
        assert_eq!(dim % 6, 2);
        assert_eq!(dim / 6, 341);
        // pad + 2 * (per_axis*3) == dim
        assert_eq!(2 + 2 * (341 * 3), dim);
    }

    #[test]
    fn rope_front_pad_is_identity() {
        let rope = Rope3D::build(2, 2, 2, LTX_HIDDEN, LTX_THETA);
        for tok in 0..rope.tokens {
            let base = tok * rope.dim;
            // first dim%6 = 2 dims are identity
            for d in 0..2 {
                assert_eq!(rope.cos[base + d], 1.0);
                assert_eq!(rope.sin[base + d], 0.0);
            }
        }
    }

    #[test]
    fn rope_token0_origin_is_near_identity_on_axes_but_not_freqs() {
        // token 0 = (f=0,h=0,w=0): coord*2-1 = -1 on all axes, so freqs are nonzero.
        let rope = Rope3D::build(1, 1, 1, LTX_HIDDEN, LTX_THETA);
        // a 2-pi-periodic check: cos^2+sin^2 == 1 everywhere
        for i in 0..rope.dim {
            let c = rope.cos[i];
            let s = rope.sin[i];
            assert!((c * c + s * s - 1.0).abs() < 1e-4);
        }
    }
}
